// JSON-Daten aus dem Payload (für das Beispiel, ersetzen mit deinen Daten)
let data = msg.payload.result;

// Ermittlung der maximalen Länge der Arrays
let maxLength = Math.max(data.Netzeinspeisung_Wh_pro_Stunde.length, data.Netzbezug_Wh_pro_Stunde.length, data.akku_soc_pro_stunde.length, data.Last_Wh_pro_Stunde.length);

// Startzeitpunkt ab der jetzigen Stunde in der lokalen Zeitzone
const intervalSeconds = Number(
    msg.optimization_interval_seconds ??
    flow.get("eos_optimization_interval_seconds") ??
    900
);
if (![900, 3600].includes(intervalSeconds)) {
    node.error(`Unsupported EOS interval: ${intervalSeconds} seconds`, msg);
    return null;
}
const intervalMinutes = intervalSeconds / 60;
const intervalMs = intervalSeconds * 1000;

// Align to the same local slot as EOS (:00/:15/:30/:45 at 900 seconds).
let now = msg.eos_start_datetime ? new Date(msg.eos_start_datetime) : new Date();
if (Number.isNaN(now.getTime())) {
    node.error("Invalid msg.eos_start_datetime", msg);
    return null;
}
now.setMinutes(Math.floor(now.getMinutes() / intervalMinutes) * intervalMinutes, 0, 0);

// Initialisierung des SQL-Statements
let sqlStatements = "";

// Schleife über die Anzahl der Stunden
for (let i = 0; i < maxLength; i++) {
    // Berechnung des Zeitstempels für jede Stunde in der lokalen Zeit
    let localTimestamp = new Date(now.getTime() + i * intervalMs);
    //let todayMidnight = new Date(now.getFullYear(), now.getMonth(), now.getDate()); // 0:00 Uhr heute

    // Optional: Falls du i nutzen möchtest, um Stunden hinzuzufügen:
    //let localTimestamp = new Date(todayMidnight.getTime() + i * intervalMs);


    // Manuelle Formatierung in das MariaDB-Format YYYY-MM-DD HH:MM:SS
    let year = localTimestamp.getFullYear();
    let month = ('0' + (localTimestamp.getMonth() + 1)).slice(-2);
    let day = ('0' + localTimestamp.getDate()).slice(-2);
    let hours = ('0' + localTimestamp.getHours()).slice(-2);
    let minutes = ('0' + localTimestamp.getMinutes()).slice(-2);
    let seconds = ('0' + localTimestamp.getSeconds()).slice(-2);

    // Formatierung für MariaDB
    let timestamp = `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
    // Prüfen, ob es für diese Stunde überhaupt Daten gibt
    let hasData = false;
    let hourSqlStatements = "";
    //node.warn(String(i) + " - "+String(data.Last_Wh_pro_Stunde[i]) + " "+ String(data.Netzeinspeisung_Wh_pro_Stunde[i]) + " "+ String(data.Netzbezug_Wh_pro_Stunde[i]))
    // Einfügen der Netzeinspeisung, wenn der Wert nicht null oder undefined ist
    if (i < data.Netzeinspeisung_Wh_pro_Stunde.length && data.Netzeinspeisung_Wh_pro_Stunde[i] != null ) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Netzeinspeisung_Wh_pro_Stunde', ROUND(${data.Netzeinspeisung_Wh_pro_Stunde[i]},8), '${timestamp}');\n`;
        hasData = true;
   }
    if (i < data.Electricity_price.length && data.Electricity_price[i] != null) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Electricity_price', ROUND(${data.Electricity_price[i]},8), '${timestamp}');\n`;
        hasData = true;
    }

    // Einfügen des Netzbezugs, wenn der Wert nicht null oder undefined ist
    if (i < data.Netzbezug_Wh_pro_Stunde.length && data.Netzbezug_Wh_pro_Stunde[i] != null ) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Netzbezug_Wh_pro_Stunde', ROUND(${data.Netzbezug_Wh_pro_Stunde[i]},8), '${timestamp}');\n`;
        hasData = true;
    }

    // Einfügen des Akkustands (SoC), wenn der Wert nicht null oder undefined ist nicht bei hasData berücksichtigen!
    if (i < data.akku_soc_pro_stunde.length && data.akku_soc_pro_stunde[i] != null ) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('akku_soc_pro_stunde',  ROUND(${data.akku_soc_pro_stunde[i]},8), '${timestamp}');\n`;
        //hasData = true;
    }

    // Einfügen der Last, wenn der Wert nicht null oder undefined ist
    if (i < data.Last_Wh_pro_Stunde.length && data.Last_Wh_pro_Stunde[i] != null  ) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('last_pro_stunde', ROUND(${data.Last_Wh_pro_Stunde[i]},8), '${timestamp}');\n`;
        //node.warn(`INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('last_pro_stunde', ROUND(${data.Last_Wh_pro_Stunde[i]},8), '${timestamp}');`);
        hasData = true;
    }

    // --- Neu: DV-relevante Werte ---
    if (i < data.Einnahmen_Euro_pro_Stunde.length && data.Einnahmen_Euro_pro_Stunde[i] != null) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Einnahmen_Euro_pro_Stunde', ROUND(${data.Einnahmen_Euro_pro_Stunde[i]},8), '${timestamp}');\n`;
    }
    if (i < data.Kosten_Euro_pro_Stunde.length && data.Kosten_Euro_pro_Stunde[i] != null) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Kosten_Euro_pro_Stunde', ROUND(${data.Kosten_Euro_pro_Stunde[i]},8), '${timestamp}');\n`;
    }
    if (i < data.Verluste_Pro_Stunde.length && data.Verluste_Pro_Stunde[i] != null) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Verluste_Pro_Stunde', ROUND(${data.Verluste_Pro_Stunde[i]},8), '${timestamp}');\n`;
    }
    if (i < data.Feed_in_tariff.length && data.Feed_in_tariff[i] != null) {
        hourSqlStatements += `INSERT INTO eos_simulation_data (topic, data, timestamp) VALUES ('Feed_in_tariff', ROUND(${data.Feed_in_tariff[i]},10), '${timestamp}');\n`;
    }

    // Nur wenn für diese Stunde Daten vorhanden sind, die Anweisungen generieren
    if (hasData) {

        sqlStatements += `DELETE FROM eos_simulation_data WHERE timestamp = '${timestamp}';\n`;
        sqlStatements += hourSqlStatements;

    }
}

// Das generierte SQL-Statement in msg.topic einfügen
msg.topic = sqlStatements;
msg.payload = sqlStatements;
return msg;
